export function getStateWaiverData(stateName: string): StateWaiverData | undefined {
  return STATE_WAIVER_DATA.find(
    s => s.state.toLowerCase() === stateName.toLowerCase() ||
         s.abbreviation.toLowerCase() === stateName.toLowerCase()
  );
}
